// Package generate provides the core code generation engine for Globular services.
// It parses .proto files using protoc and executes Go text/templates to produce
// service scaffolding that follows Globular conventions.
package generate

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"regexp"
	"strings"
	"text/template"
	"unicode"

	"google.golang.org/protobuf/proto"
	descriptorpb "google.golang.org/protobuf/types/descriptorpb"
)

// generatedHeader is prepended to every generated file.
const generatedHeader = "// Code generated by globular-cli; DO NOT EDIT.\n\n"

// ServiceData is the root template context for code generation.
type ServiceData struct {
	PackageName string    // proto package (e.g. "catalog")
	ServiceName string    // proto service name in PascalCase (e.g. "CatalogService")
	GoPackage   string    // from go_package option (e.g. "github.com/globulario/services/golang/catalog/catalogpb")
	ProtoFile   string    // relative proto path
	Port        int       // default port (auto-allocated or user-specified)
	RPCs        []RPCData // all RPC methods
	Messages    []MessageData
	HasAuth     bool   // has globular.auth.authz annotations
	Store       string // none/sqlite/postgres/mongodb
	Persistence string // native/ef
	Lang        string // target language (go/csharp)
	SkipSpec    bool   // skip package.yaml generation

	// Derived fields (computed by Prepare)
	ServiceNameLower string // e.g. "catalogservice"
	ServiceNameSnake string // e.g. "catalog_service"
	PbPackage        string // last segment of GoPackage (e.g. "catalogpb")
	ModulePath       string // Go module path for the service
	ProtoPackagePath string // proto package for imports
}

// RPCData describes a single RPC method.
type RPCData struct {
	Name             string
	InputType        string
	OutputType       string
	IsServerStream   bool
	IsClientStream   bool
	AuthzAction      string // from annotation
	AuthzPerm        string // read/write/delete/admin
	ResourceTemplate string // resource_template value
	DefaultRoleHint  string
}

// MessageData describes a protobuf message.
type MessageData struct {
	Name   string
	Fields []FieldData
}

// FieldData describes a single message field.
type FieldData struct {
	Name     string
	Type     string
	Number   int32
	Repeated bool
}

// Prepare computes derived fields from the primary data.
func (d *ServiceData) Prepare() {
	d.ServiceNameLower = strings.ToLower(d.ServiceName)
	d.ServiceNameSnake = toSnakeCase(d.ServiceName)
	if d.GoPackage != "" {
		parts := strings.Split(d.GoPackage, "/")
		d.PbPackage = parts[len(parts)-1]
	}
	if d.ModulePath == "" && d.GoPackage != "" {
		// Derive module path: strip the pb package suffix
		idx := strings.LastIndex(d.GoPackage, "/")
		if idx > 0 {
			d.ModulePath = d.GoPackage[:idx]
		}
	}
}

// ParseProto uses protoc to parse a .proto file and extract service/message definitions.
func ParseProto(protoFile string) (*ServiceData, error) {
	absProto, err := filepath.Abs(protoFile)
	if err != nil {
		return nil, fmt.Errorf("resolve proto path: %w", err)
	}

	if _, err := os.Stat(absProto); err != nil {
		return nil, fmt.Errorf("proto file not found: %s", absProto)
	}

	// Determine include paths
	protoDir := filepath.Dir(absProto)
	includeArgs := []string{"-I", protoDir}

	// Add standard proto include paths
	for _, p := range []string{
		"/usr/include",
		"/usr/local/include",
		filepath.Join(protoDir, ".."),
	} {
		if info, err := os.Stat(p); err == nil && info.IsDir() {
			includeArgs = append(includeArgs, "-I", p)
		}
	}

	// Create temp file for descriptor set
	tmpFile, err := os.CreateTemp("", "globular-proto-*.pb")
	if err != nil {
		return nil, fmt.Errorf("create temp file: %w", err)
	}
	defer os.Remove(tmpFile.Name())
	tmpFile.Close()

	// Run protoc
	args := append(includeArgs, "--descriptor_set_out="+tmpFile.Name(), "--include_source_info", absProto)
	cmd := exec.Command("protoc", args...)
	var stderr bytes.Buffer
	cmd.Stderr = &stderr
	if err := cmd.Run(); err != nil {
		return nil, fmt.Errorf("protoc failed: %v\n%s", err, stderr.String())
	}

	// Read and parse descriptor set
	descData, err := os.ReadFile(tmpFile.Name())
	if err != nil {
		return nil, fmt.Errorf("read descriptor: %w", err)
	}

	var fdSet descriptorpb.FileDescriptorSet
	if err := proto.Unmarshal(descData, &fdSet); err != nil {
		return nil, fmt.Errorf("unmarshal descriptor: %w", err)
	}

	if len(fdSet.GetFile()) == 0 {
		return nil, fmt.Errorf("no files in descriptor set")
	}

	return extractServiceData(fdSet.GetFile()[0], protoFile)
}

func extractServiceData(fd *descriptorpb.FileDescriptorProto, protoFile string) (*ServiceData, error) {
	data := &ServiceData{
		PackageName: fd.GetPackage(),
		ProtoFile:   protoFile,
		Store:       "none",
		Persistence: "native",
	}

	// Extract go_package option
	if opts := fd.GetOptions(); opts != nil {
		if goPkg := opts.GetGoPackage(); goPkg != "" {
			data.GoPackage = goPkg
		}
	}

	// Extract messages
	for _, msg := range fd.GetMessageType() {
		md := MessageData{Name: msg.GetName()}
		for _, field := range msg.GetField() {
			fd := FieldData{
				Name:     field.GetName(),
				Type:     protoTypeToString(field.GetType()),
				Number:   field.GetNumber(),
				Repeated: field.GetLabel() == descriptorpb.FieldDescriptorProto_LABEL_REPEATED,
			}
			md.Fields = append(md.Fields, fd)
		}
		data.Messages = append(data.Messages, md)
	}

	// Extract services
	for _, svc := range fd.GetService() {
		data.ServiceName = svc.GetName()

		for _, method := range svc.GetMethod() {
			rpc := RPCData{
				Name:           method.GetName(),
				InputType:      lastSegment(method.GetInputType()),
				OutputType:     lastSegment(method.GetOutputType()),
				IsServerStream: method.GetServerStreaming(),
				IsClientStream: method.GetClientStreaming(),
			}
			// Authz annotations are extracted via regex fallback (ParseProtoFallback)
			// since protoc does not resolve custom extensions into the descriptor set
			// without the extension proto compiled in.
			data.RPCs = append(data.RPCs, rpc)
		}
		break // Only process first service
	}

	if data.ServiceName == "" {
		return nil, fmt.Errorf("no service definition found in %s", protoFile)
	}

	return data, nil
}

// ParseProtoFallback uses regex-based parsing when protoc is not available
// or when extension parsing fails. It provides basic extraction of service
// definitions and authz annotations.
func ParseProtoFallback(protoFile string) (*ServiceData, error) {
	content, err := os.ReadFile(protoFile)
	if err != nil {
		return nil, fmt.Errorf("read proto file: %w", err)
	}

	data := &ServiceData{
		ProtoFile:   protoFile,
		Store:       "none",
		Persistence: "native",
	}

	text := string(content)

	// Extract package
	if m := regexp.MustCompile(`package\s+(\S+)\s*;`).FindStringSubmatch(text); len(m) > 1 {
		data.PackageName = m[1]
	}

	// Extract go_package
	if m := regexp.MustCompile(`option\s+go_package\s*=\s*"([^"]+)"`).FindStringSubmatch(text); len(m) > 1 {
		data.GoPackage = m[1]
	}

	// Extract service name
	if m := regexp.MustCompile(`service\s+(\w+)\s*\{`).FindStringSubmatch(text); len(m) > 1 {
		data.ServiceName = m[1]
	} else {
		return nil, fmt.Errorf("no service definition found in %s", protoFile)
	}

	// Extract RPCs
	rpcRe := regexp.MustCompile(`rpc\s+(\w+)\s*\(\s*(stream\s+)?(\w+)\s*\)\s*returns\s*\(\s*(stream\s+)?(\w+)\s*\)`)
	for _, m := range rpcRe.FindAllStringSubmatch(text, -1) {
		rpc := RPCData{
			Name:           m[1],
			InputType:      m[3],
			OutputType:     m[5],
			IsClientStream: m[2] != "",
			IsServerStream: m[4] != "",
		}
		data.RPCs = append(data.RPCs, rpc)
	}

	// Extract authz annotations
	authzRe := regexp.MustCompile(`option\s+\(globular\.auth\.authz\)\s*=\s*\{([^}]+)\}`)
	actionRe := regexp.MustCompile(`action:\s*"([^"]+)"`)
	permRe := regexp.MustCompile(`permission:\s*"([^"]+)"`)
	resTmplRe := regexp.MustCompile(`resource_template:\s*"([^"]+)"`)
	roleHintRe := regexp.MustCompile(`default_role_hint:\s*"([^"]+)"`)

	// Match each authz block to its preceding rpc
	rpcPositions := rpcRe.FindAllStringIndex(text, -1)
	authzMatches := authzRe.FindAllStringSubmatchIndex(text, -1)

	for i, rpcPos := range rpcPositions {
		if i >= len(data.RPCs) {
			break
		}
		// Find authz annotation between this rpc and the next
		nextRpcStart := len(text)
		if i+1 < len(rpcPositions) {
			nextRpcStart = rpcPositions[i+1][0]
		}

		for _, authzIdx := range authzMatches {
			if authzIdx[0] > rpcPos[0] && authzIdx[0] < nextRpcStart {
				block := text[authzIdx[2]:authzIdx[3]]
				if m := actionRe.FindStringSubmatch(block); len(m) > 1 {
					data.RPCs[i].AuthzAction = m[1]
					data.HasAuth = true
				}
				if m := permRe.FindStringSubmatch(block); len(m) > 1 {
					data.RPCs[i].AuthzPerm = m[1]
				}
				if m := resTmplRe.FindStringSubmatch(block); len(m) > 1 {
					data.RPCs[i].ResourceTemplate = m[1]
				}
				if m := roleHintRe.FindStringSubmatch(block); len(m) > 1 {
					data.RPCs[i].DefaultRoleHint = m[1]
				}
				break
			}
		}
	}

	// Extract messages
	msgRe := regexp.MustCompile(`message\s+(\w+)\s*\{([^}]*)\}`)
	fieldRe := regexp.MustCompile(`(?:repeated\s+)?(\w+)\s+(\w+)\s*=\s*(\d+)`)
	for _, m := range msgRe.FindAllStringSubmatch(text, -1) {
		md := MessageData{Name: m[1]}
		for _, f := range fieldRe.FindAllStringSubmatch(m[2], -1) {
			fd := FieldData{
				Type:     f[1],
				Name:     f[2],
				Repeated: strings.Contains(m[0], "repeated "+f[1]),
			}
			md.Fields = append(md.Fields, fd)
		}
		data.Messages = append(data.Messages, md)
	}

	return data, nil
}

// GenerateFiles generates service files for the specified language.
func GenerateFiles(data *ServiceData, lang, outDir string, dryRun bool) ([]string, error) {
	data.Prepare()

	var templates map[string]string
	switch lang {
	case "go":
		templates = GoTemplates(data)
	case "csharp":
		templates = CSharpTemplates(data)
	default:
		return nil, fmt.Errorf("unsupported language: %s (supported: go, csharp)", lang)
	}

	var files []string
	for relPath, tmplContent := range templates {
		fullPath := filepath.Join(outDir, relPath)
		files = append(files, fullPath)

		if dryRun {
			continue
		}

		dir := filepath.Dir(fullPath)
		if err := os.MkdirAll(dir, 0755); err != nil {
			return nil, fmt.Errorf("create dir %s: %w", dir, err)
		}

		tmpl, err := template.New(relPath).Funcs(templateFuncs()).Parse(tmplContent)
		if err != nil {
			return nil, fmt.Errorf("parse template %s: %w", relPath, err)
		}

		var buf bytes.Buffer
		if err := tmpl.Execute(&buf, data); err != nil {
			return nil, fmt.Errorf("execute template %s: %w", relPath, err)
		}

		if err := os.WriteFile(fullPath, buf.Bytes(), 0644); err != nil {
			return nil, fmt.Errorf("write %s: %w", fullPath, err)
		}
	}

	return files, nil
}

// GenerateServiceOnly generates only the server files (no client, no tests).
func GenerateServiceOnly(data *ServiceData, lang, outDir string, dryRun bool) ([]string, error) {
	data.Prepare()

	var templates map[string]string
	switch lang {
	case "go":
		templates = GoServerTemplates(data)
	case "csharp":
		templates = CSharpTemplates(data) // C# generates all-or-nothing
	default:
		return nil, fmt.Errorf("unsupported language: %s", lang)
	}

	var files []string
	for relPath, tmplContent := range templates {
		fullPath := filepath.Join(outDir, relPath)
		files = append(files, fullPath)

		if dryRun {
			continue
		}

		dir := filepath.Dir(fullPath)
		if err := os.MkdirAll(dir, 0755); err != nil {
			return nil, fmt.Errorf("create dir %s: %w", dir, err)
		}

		tmpl, err := template.New(relPath).Funcs(templateFuncs()).Parse(tmplContent)
		if err != nil {
			return nil, fmt.Errorf("parse template %s: %w", relPath, err)
		}

		var buf bytes.Buffer
		if err := tmpl.Execute(&buf, data); err != nil {
			return nil, fmt.Errorf("execute template %s: %w", relPath, err)
		}

		if err := os.WriteFile(fullPath, buf.Bytes(), 0644); err != nil {
			return nil, fmt.Errorf("write %s: %w", fullPath, err)
		}
	}

	return files, nil
}

// templateFuncs returns the template function map.
func templateFuncs() template.FuncMap {
	return template.FuncMap{
		"toLower":     strings.ToLower,
		"toUpper":     strings.ToUpper,
		"toPascal":    toPascalCase,
		"toCamel":     toCamelCase,
		"toSnake":     toSnakeCase,
		"lastSegment": lastSegment,
		"add":         func(a, b int) int { return a + b },
		"hasPrefix":   strings.HasPrefix,
		"hasSuffix":   strings.HasSuffix,
		"trimSuffix":  strings.TrimSuffix,
		"stateDir":    func() string { return "{{.StateDir}}" },
		"prefix":      func() string { return "{{.Prefix}}" },
	}
}

// GenerateSpecOnly generates only the package.yaml spec file.
func GenerateSpecOnly(data *ServiceData, lang, outDir string, dryRun bool) ([]string, error) {
	data.Prepare()

	templates := SpecTemplate(data, lang)

	var files []string
	for relPath, tmplContent := range templates {
		fullPath := filepath.Join(outDir, relPath)
		files = append(files, fullPath)

		if dryRun {
			continue
		}

		dir := filepath.Dir(fullPath)
		if err := os.MkdirAll(dir, 0755); err != nil {
			return nil, fmt.Errorf("create dir %s: %w", dir, err)
		}

		tmpl, err := template.New(relPath).Funcs(templateFuncs()).Parse(tmplContent)
		if err != nil {
			return nil, fmt.Errorf("parse template %s: %w", relPath, err)
		}

		var buf bytes.Buffer
		if err := tmpl.Execute(&buf, data); err != nil {
			return nil, fmt.Errorf("execute template %s: %w", relPath, err)
		}

		if err := os.WriteFile(fullPath, buf.Bytes(), 0644); err != nil {
			return nil, fmt.Errorf("write %s: %w", fullPath, err)
		}
	}

	return files, nil
}

// ── Helpers ──────────────────────────────────────────────────────────────────

func toSnakeCase(s string) string {
	var result []rune
	for i, r := range s {
		if unicode.IsUpper(r) {
			if i > 0 {
				prev := rune(s[i-1])
				if unicode.IsLower(prev) {
					result = append(result, '_')
				} else if unicode.IsUpper(prev) && i+1 < len(s) && unicode.IsLower(rune(s[i+1])) {
					result = append(result, '_')
				}
			}
			result = append(result, unicode.ToLower(r))
		} else {
			result = append(result, r)
		}
	}
	return string(result)
}

func toPascalCase(s string) string {
	parts := strings.FieldsFunc(s, func(r rune) bool {
		return r == '_' || r == '-' || r == '.'
	})
	for i, p := range parts {
		if len(p) > 0 {
			parts[i] = strings.ToUpper(p[:1]) + p[1:]
		}
	}
	return strings.Join(parts, "")
}

func toCamelCase(s string) string {
	p := toPascalCase(s)
	if len(p) == 0 {
		return p
	}
	return strings.ToLower(p[:1]) + p[1:]
}

func lastSegment(s string) string {
	if idx := strings.LastIndex(s, "."); idx >= 0 {
		return s[idx+1:]
	}
	return s
}

func protoTypeToString(t descriptorpb.FieldDescriptorProto_Type) string {
	switch t {
	case descriptorpb.FieldDescriptorProto_TYPE_STRING:
		return "string"
	case descriptorpb.FieldDescriptorProto_TYPE_INT32, descriptorpb.FieldDescriptorProto_TYPE_SINT32:
		return "int32"
	case descriptorpb.FieldDescriptorProto_TYPE_INT64, descriptorpb.FieldDescriptorProto_TYPE_SINT64:
		return "int64"
	case descriptorpb.FieldDescriptorProto_TYPE_UINT32:
		return "uint32"
	case descriptorpb.FieldDescriptorProto_TYPE_UINT64:
		return "uint64"
	case descriptorpb.FieldDescriptorProto_TYPE_FLOAT:
		return "float"
	case descriptorpb.FieldDescriptorProto_TYPE_DOUBLE:
		return "double"
	case descriptorpb.FieldDescriptorProto_TYPE_BOOL:
		return "bool"
	case descriptorpb.FieldDescriptorProto_TYPE_BYTES:
		return "bytes"
	case descriptorpb.FieldDescriptorProto_TYPE_MESSAGE:
		return "message"
	case descriptorpb.FieldDescriptorProto_TYPE_ENUM:
		return "enum"
	default:
		return t.String()
	}
}
